// src/services/api.js
import { mockGroups } from '../mocks/mockGroups';

export const fetchGroups = () => {
    return new Promise((resolve) => {
        setTimeout(() => {
            resolve(mockGroups);
        }, 500); // simulate network delay
    });
};
